package com.example.mfa.service;

import com.example.mfa.dto.*;
import com.example.mfa.model.AppUser;
import com.example.mfa.model.BackupCode;
import com.example.mfa.repository.AppUserRepository;
import com.example.mfa.repository.BackupCodeRepository;
import lombok.RequiredArgsConstructor;
import org.apache.commons.codec.binary.Base32;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Service
@RequiredArgsConstructor
public class AuthService {

    private static final int BACKUP_CODE_COUNT = 10;

    private final AppUserRepository appUserRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final AuthenticationManager authenticationManager;

    @Transactional
    public void register(RegisterRequest request) {
        if (appUserRepository.existsByUsername(request.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }

        AppUser user = AppUser.builder()
            .username(request.getUsername())
            .password(passwordEncoder.encode(request.getPassword()))
            .mfaEnabled(false)
            .accountNonLocked(true)
            .enabled(true)
            .build();

        appUserRepository.save(user);
    }

    public AuthResponse login(LoginRequest request) {
        authenticationManager.authenticate(
            new UsernamePasswordAuthenticationToken(request.getUsername(), request.getPassword())
        );

        AppUser user = appUserRepository.findByUsername(request.getUsername())
            .orElseThrow(() -> new IllegalArgumentException("User not found"));

        if (user.isMfaEnabled()) {
            return new AuthResponse("Primary authentication successful. MFA required.", true);
        }

        return new AuthResponse("Authentication successful.", false);
    }

    @Transactional
    public MfaEnableResponse enableMfaAndGenerateBackupCodes(String username) {
        AppUser user = appUserRepository.findByUsername(username)
            .orElseThrow(() -> new IllegalArgumentException("User not found"));

        String secret = generateSecret();
        user.setMfaSecret(secret);
        user.setMfaEnabled(true);

        backupCodeRepository.deleteAll(user.getBackupCodes());
        user.getBackupCodes().clear();

        List<String> plainCodes = new ArrayList<>();
        for (int i = 0; i < BACKUP_CODE_COUNT; i++) {
            String code = generateBackupCode();
            plainCodes.add(code);

            BackupCode backupCode = BackupCode.builder()
                .codeHash(passwordEncoder.encode(code))
                .used(false)
                .user(user)
                .build();

            user.getBackupCodes().add(backupCode);
        }

        appUserRepository.save(user);
        return new MfaEnableResponse(secret, plainCodes);
    }

    @Transactional
    public BackupCodeRedeemResponse authenticateWithBackupCode(BackupCodeLoginRequest request) {
        authenticationManager.authenticate(
            new UsernamePasswordAuthenticationToken(request.getUsername(), request.getPassword())
        );

        AppUser user = appUserRepository.findByUsername(request.getUsername())
            .orElseThrow(() -> new IllegalArgumentException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new IllegalStateException("MFA is not enabled for this user");
        }

        List<BackupCode> availableCodes = backupCodeRepository.findByUserAndUsedFalse(user);
        BackupCode matched = availableCodes.stream()
            .filter(code -> passwordEncoder.matches(normalizeBackupCode(request.getBackupCode()), code.getCodeHash()))
            .findFirst()
            .orElseThrow(() -> new IllegalArgumentException("Invalid backup code"));

        matched.setUsed(true);
        matched.setUsedAt(Instant.now());
        backupCodeRepository.save(matched);

        int remaining = (int) backupCodeRepository.findByUserAndUsedFalse(user).stream().count();
        return new BackupCodeRedeemResponse("Authenticated using backup code.", remaining);
    }

    private String generateSecret() {
        byte[] buffer = new byte[20];
        new SecureRandom().nextBytes(buffer);
        return new Base32().encodeToString(buffer).replace("=", "");
    }

    private String generateBackupCode() {
        String raw = UUID.randomUUID().toString().replace("-", "").substring(0, 10).toUpperCase();
        return raw.substring(0, 5) + "-" + raw.substring(5);
    }

    private String normalizeBackupCode(String code) {
        return code == null ? null : code.trim().toUpperCase();
    }
}

package com.example.mfa.controller;

import com.example.mfa.dto.*;
import com.example.mfa.service.AuthService;
import lombok.RequiredArgsConstructor;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
@RequiredArgsConstructor
public class AuthController {

    private final AuthService authService;

    @PostMapping("/register")
    public void register(@RequestBody RegisterRequest request) {
        authService.register(request);
    }

    @PostMapping("/login")
    public AuthResponse login(@RequestBody LoginRequest request) {
        return authService.login(request);
    }

    @PostMapping("/mfa/enable")
    public MfaEnableResponse enableMfa(Authentication authentication) {
        return authService.enableMfaAndGenerateBackupCodes(authentication.getName());
    }

    @PostMapping("/mfa/backup-code/login")
    public BackupCodeRedeemResponse loginWithBackupCode(@RequestBody BackupCodeLoginRequest request) {
        return authService.authenticateWithBackupCode(request);
    }
}

