package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import com.example.mfa.model.BackupCode;
import com.example.mfa.repository.AppUserRepository;
import com.example.mfa.repository.BackupCodeRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.ArrayList;
import java.util.List;

@Service
@RequiredArgsConstructor
public class BackupCodeService {

    private static final int BACKUP_CODE_COUNT = 10;

    private final AppUserRepository appUserRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;

    @Transactional
    public List<String> regenerateBackupCodes(String username) {
        AppUser user = appUserRepository.findByUsername(username)
            .orElseThrow(() -> new IllegalArgumentException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new IllegalStateException("Cannot generate backup codes when MFA is disabled");
        }

        backupCodeRepository.deleteAll(user.getBackupCodes());
        user.getBackupCodes().clear();

        List<String> plainCodes = new ArrayList<>();
        for (int i = 0; i < BACKUP_CODE_COUNT; i++) {
            String code = java.util.UUID.randomUUID().toString().replace("-", "").substring(0, 10).toUpperCase();
            code = code.substring(0, 5) + "-" + code.substring(5);
            plainCodes.add(code);

            BackupCode backupCode = BackupCode.builder()
                .codeHash(passwordEncoder.encode(code))
                .used(false)
                .user(user)
                .build();
            user.getBackupCodes().add(backupCode);
        }

        appUserRepository.save(user);
        return plainCodes;
    }
}

